package main

import (
	"strings"
	"testing"
)

func TestEmitConfigGen_EmptyConfig(t *testing.T) {
	t.Parallel()

	spec, err := inferFromYAML(nil)
	if err != nil {
		t.Fatalf("inferFromYAML: %v", err)
	}
	types := finalize(spec)

	got := emitConfigGen("default", types)

	for _, want := range []string{
		"// Code generated by themegen. DO NOT EDIT.",
		"package theme",
		"type Config struct {",
		"var Cfg Config",
	} {
		if !strings.Contains(got, want) {
			t.Errorf("output missing %q\n--- output ---\n%s", want, got)
		}
	}
}

func TestEmitConfigGen_ScalarFields(t *testing.T) {
	t.Parallel()

	input := `DevTools: true
MaxItems: 6
PrimaryColor: "#0f172a"
`
	spec, err := inferFromYAML([]byte(input))
	if err != nil {
		t.Fatalf("inferFromYAML: %v", err)
	}
	types := finalize(spec)

	got := emitConfigGen("default", types)

	for _, want := range []string{
		"DevTools     bool",
		"MaxItems     int",
		"PrimaryColor string",
	} {
		if !strings.Contains(got, want) {
			t.Errorf("output missing %q\n--- output ---\n%s", want, got)
		}
	}
}

func TestEmitConfigGen_NestedAndRecursive(t *testing.T) {
	t.Parallel()

	input := `Branding:
  Logo: ""
  Discord: ""
Navbar:
  Items:
    - Label: "Home"
      Href: "/"
      Icon: "home"
      Children:
        - Label: "Sub"
          Href: "/sub"
          Icon: "x"
          Children:
            - Label: "Leaf"
              Href: "/leaf"
              Icon: "y"
              Children:
                - Label: "Tip"
                  Href: "/tip"
                  Icon: "z"
`
	spec, err := inferFromYAML([]byte(input))
	if err != nil {
		t.Fatalf("inferFromYAML: %v", err)
	}
	types := finalize(spec)

	got := emitConfigGen("default", types)

	for _, want := range []string{
		"type Branding struct",
		"type Navbar struct",
		"type NavbarItem struct",
		"Items    []NavbarItem",
		"Children []NavbarItem",
	} {
		if !strings.Contains(got, want) {
			t.Errorf("output missing %q\n--- output ---\n%s", want, got)
		}
	}
}

func TestEmitConfigGen_NoBuildTagForDefault(t *testing.T) {
	t.Parallel()

	spec, err := inferFromYAML([]byte(`Key: "value"`))
	if err != nil {
		t.Fatalf("inferFromYAML: %v", err)
	}
	types := finalize(spec)

	got := emitConfigGen("default", types)

	if strings.Contains(got, "//go:build") {
		t.Errorf("default config_gen should not have a build tag, got:\n%s", got)
	}
}
